mapper.select:
SELECT ce.`id`, ce.`organizer_id`, u.`display_name` AS organizer_name, u.`avatar_url`, ce.`title`, ce.`court_id`, COALESCE(ce.`court_name`, c.`name`) AS court_name, COALESCE(ce.`country`, c.`country`) AS country, COALESCE(ce.`province`, c.`province`) AS province, COALESCE(ce.`city`, c.`city`) AS city, ce.`district`, ce.`started_at`, ce.`ended_at`, ce.`match_type`, ce.`needed_players`, ce.`min_level`, ce.`max_level`, ce.`price_mode`, ce.`price_per_person`, ce.`gender_requirement`, ce.`note` FROM `ir_club`.`club_events` ce LEFT JOIN `ir_auth`.`users` u ON u.`id` = ce.`organizer_id` AND u.`status` = 0 AND u.`deleted_at` IS NULL LEFT JOIN `ir_profile`.`courts` c ON c.`id` = ce.`court_id` AND c.`status` = 0 WHERE ce.`status` = 0 AND ce.`event_status` IN ('upcoming', 'ongoing') AND ce.`started_at` >= DATE_SUB(NOW(), INTERVAL 12 HOUR)
AND COALESCE(ce.`country`, c.`country`) = #{country}
AND COALESCE(ce.`province`, c.`province`) = #{province}
AND COALESCE(ce.`city`, c.`city`) = #{city}
ORDER BY ce.`started_at` ASC, ce.`created_at` DESC LIMIT 100

SELECT COUNT(*)
FROM `ir_profile`.`court_likes`
WHERE `court_id` = #{courtId}
  AND `user_id` = #{userId}
  AND `status` = 0

SELECT COUNT(*)
FROM `ir_profile`.`profile_edit_audit_logs`
WHERE `user_id` = #{userId}
  AND `field_name` = #{fieldName}
  AND `status` = 0
  AND `created_at` >= #{since}

SELECT COUNT(*)
FROM `ir_activity`.`player_relationship_edges`
WHERE `user_id` = #{userId}
  AND `peer_user_id` = #{targetUserId}
  AND `status` = 0
